      reviewTable: [['Trámite','Regla clave'],['Inicio de oficio','Iniciativa, orden, petición razonada o denuncia'],['Medida previa','Confirmación/modificación/levantamiento en 15 días'],['Solicitud','Contenido legal y órgano destinatario'],['Subsanación','Diez días; advertencia de desistimiento'],['Declaración responsable','Cumplimiento bajo responsabilidad y control posterior'],['Expediente','Conjunto ordenado con índice y autenticidad'],['Impulso','De oficio y electrónico'],['Prueba','Periodo de 10 a 30 días'],['Informe','Facultativo/no vinculante salvo norma; normalmente 10 días'],['Audiencia','Entre 10 y 15 días'],['Información pública','Mínimo 20 días'],['Resolución','Decide todas las cuestiones'],['Caducidad a solicitud','Tres meses tras advertencia si trámite indispensable'],['Simplificada','Resolución general en 30 días y trámites tasados']]
